import pandas as pd
import json

def clean_data(df):
    def parse_metadata(meta_str):
        if pd.isna(meta_str):
            return pd.Series([None, None])
        try:
            meta = json.loads(meta_str)
            category = meta.get("category")
            warranty = meta.get("warranty_years")
            return pd.Series([category, warranty])
        except (json.JSONDecodeError, TypeError, ValueError):
            return pd.Series([None, None])

    df[["metadata_category", "metadata_warranty_years"]] = df["metadata"].apply(parse_metadata)
    df.drop(columns=["metadata"], inplace=True)
    return df

import pandas as pd
import re

def clean_data(df):
    def extract_id(val):
        if pd.isna(val):
            return pd.NA
        s = str(val).strip()
        if not s:
            return pd.NA
        match = re.search(r'(\d+)', s)
        if match:
            return f"U-{match.group(1)}"
        else:
            return pd.NA
    df['user_id'] = df['user_id'].apply(extract_id)
    return df
